def generate_device_id():
    try:
        system_info = {
            'euid': os.geteuid(),
            'username': os.getlogin(),
            'hostname': os.uname().nodename,
            'machine': os.uname().machine
        }
        unique_string = f"{system_info['euid']}-{system_info['username']}-{system_info['hostname']}-{system_info['machine']}"
        return hashlib.sha256(unique_string.encode()).hexdigest()
    except Exception as e:
        console.print(f"[bold red]Error generating device ID: {e}[/bold red]")
        sys.exit(1)

def check_github_approval(device_id):
    try:
        headers = {'Cache-Control': 'no-cache', 'Pragma': 'no-cache'}
        response = requests.get(LICENSE_URL, headers=headers, timeout=15)
        response.raise_for_status()
        approved_keys = [line.strip() for line in response.text.splitlines() if line.strip() and not line.startswith('#')]
        return device_id in approved_keys
    except:
        return False

