    acc_info.add(f"[white]Gender   : [bold bright_cyan]{gender}[/bold bright_cyan]")

    # Contact
    contact = tree.add("[bold bright_cyan]Contact[/bold bright_cyan]")
    contact.add(f"[white]Email    : [bold bright_cyan]{email}[/bold bright_cyan]")

    # Cookie (lengkap)
    cookie_tree = tree.add("[bold bright_cyan]Cookie (Full)[/bold bright_cyan]")
    cookie_tree.add(f"[dim bright_cyan]{cookies}[/dim bright_cyan]")

    # Device & Session
    dev = tree.add("[bold bright_green]Device & Session[/bold bright_green]")
    dev.add(f"[white]User-Agent : [bold bright_cyan]{user_agent}[/bold bright_cyan]")
    dev.add(f"[white]Timestamp  : [bold bright_cyan]{datetime.datetime.now().strftime('%Y-%m-%d %H:%M:%S')}[/bold bright_cyan]")

    console.print(tree)

