    def GetTimeStamp(self):
        tahun = str(random.randint(1980, 2010))
        bulan = str(random.randint(1, 12))
        tanggal = str(random.randint(1, 29))
        jam = str(random.randint(0, 23))
        menit = str(random.randint(1, 59))
        detik = str(random.randint(1, 59))
        date = datetime.datetime(int(tahun), int(bulan), int(tanggal), int(jam), int(menit), int(detik))
        timestamp = int(date.replace(tzinfo=datetime.timezone.utc).timestamp())
        return (timestamp, tahun, bulan, tanggal)

    def GetNumber(self):
        data = str(random.choice(['+62896', '+62831', '+62882', '+62858', '+62851']))
        nomor = str(random.randint(11111111, 99999999))
        return data + nomor

